```class Solution {
public:
    int maxPalindromes(string s, int k) {
        int n = s.size(), res = 0;
        vector<bool> dp(n, false);
        for (int i = n - 1; i >= 0; --i) {
            for (int j = i; j < n; ++j) {
                if (s[i] == s[j] && (j - i < 3 || dp[i + 1] && j - i > k)) {
                    dp[i] = true;
                    res = max(res, dp[i] ? res + 1 : res);
                }
            }
        }
        return res;
    }
};
